(game "Blossom"
    (players 2)
    (equipment 
        (board (square 5))
    ) 

    (rules 
        (play
            (repeat (P1 P2)
                (place (destination empty))
            )
        )

        (end 
            (if (line 5) (mover win))
            (if (full_board) (draw))    
        )
    )
    (rendering
        (color P1 red)
        (color P2 blue)
    )
)

(game "Blossom Enhanced"
    (players 2)
    (equipment 
        (board (square 5))
    ) 

    (rules 
        (play
            (repeat (P1 P2)
                (place (destination empty))
            )
        )

        (end 
            (if (>= (count (connected (edges) mover)) 5) (mover win))
            (if (full_board) (draw))    
        )
    )
    (rendering
        (color P1 red)
        (color P2 blue)
    )
)

(game "Island Hoppers"
    (players 2)
    (equipment 
        (board (square 4))
    ) 

    (rules 
        (start
            (place P1 (0 0))
            (place P2 (3 3))
        )
        (play
            (repeat (P1 P2)
                (place 
                    (destination empty)
                    (result 
                        (or 
                            (empty)
                            (and 
                                (occupied opponent)
                                (empty (adjacent direction: (if mover_is P1 up else down)))
                            )
                        )
                    )
                )
            )
        )

        (end 
            (if (or 
                    (and (mover_is P1) (>= (line 4) 1))
                    (and (mover_is P2) (>= (line 4) 3))
                )
            )
            (if (full_board) (draw))    
        )
    )
)

(game "Simple Takeover"
    (players 2)
    (equipment 
        (board (square 4))
    ) 

    (rules 
        (start
            (place P1 (2 2))
            (place P2 (3 3))
        )
        (play
            (repeat (P1 P2)
                (place 
                    (destination 
                        (and 
                            empty 
                            (or 
                                (adjacent occupied mover)
                                (adjacent occupied opponent)
                            )
                        )
                    )
                    (effects 
                        (capture (adjacent occupied opponent))
                    )
                )
            )
        )
        (end 
            (if (not (exists occupied)) (mover win))
            (if (full_board) (draw))    
        )
    )
    (rendering
        (color P1 black)
        (color P2 white)
    )
)

(game "Simple Capture"
    (players 2)
    (equipment 
        (board (square 4))
    ) 

    (rules 
        (start
            (place P1 (1 1))
            (place P2 (3 3))
        )
        (play
            (repeat (P1 P2)
                (place 
                    (destination empty)
                    (effects 
                        (capture (adjacent occupied) increment_score:true)
                    )
                )
            )
        )
        (end 
            (if (passed both) (by_score))    
        )
    )
    (rendering
        (color P1 black)
        (color P2 white)
    )
)

